beforeExample:
@Deprecated
class MyClass {
    public void foo() { 
        System.out.println("Foo");
    }

    public void bar(String s) {
        System.out.println(s);
    }

    @Deprecated
    public void baz() {
        System.out.println("Baz");
    }

    public MyClass() {
        System.out.println("Constructor");
    }
}
class AnotherClass {
    public void qux() {
        System.out.println("Qux");
    }
}

