negativeExample:
// Already deprecated method
@Deprecated
class MyClassDeprec {
    @Deprecated
    public void baz() { // Should not be matched
        System.out.println("Baz");
    }
}

// Class not deprecated
class AnotherClassReg {
    public void qux() { // Should not be matched
        System.out.println("Qux");
    }
}

// Constructor (guard !isInConstructor() should prevent match)
@Deprecated
class MyClassConstructor {
    public MyClassConstructor() { // Should not be matched
        System.out.println("Constructor");
    }
}
